import math

class Solution(object):
    def nonSpecialCount(self, l, r):
        # Special numbers have exactly 2 proper divisors => must be p^2 for prime p
        # Sieve up to sqrt(r)
        limit = int(math.isqrt(r)) + 1
        sieve = [True] * (limit + 1)
        sieve[0] = sieve[1] = False
        for i in range(2, int(math.isqrt(limit)) + 1):
            if sieve[i]:
                for j in range(i*i, limit+1, i):
                    sieve[j] = False
        # Count special numbers in [l, r]: primes p where l <= p^2 <= r
        special = sum(1 for p in range(2, limit+1) if sieve[p] and l <= p*p <= r)
        return (r - l + 1) - special
